import React from "react";
import { Chart as ChartJS, ArcElement, Tooltip, Legend } from "chart.js";
import { Doughnut, Pie } from "react-chartjs-2";

const TopBuyingPurchaser = () => {
  ChartJS.register(ArcElement, Tooltip, Legend);
   const options = {
        
    plugins: {
      legend: {
        position: 'top',
      },
      title: {
        display: true,
        text: '',
      },
      legend: {
        display: false
     }
    },
  };
   const data = {
      labels: ["cnc & sons", "Agra transport", "jaipan and co.", "miller association", "alpha corporation", "khemchand and sons"],
      datasets: [
         {
            label: "Outstanding",
            data: [100000, 50000, 70000, 360000, 78000, 50000],
            backgroundColor: [
               "rgba(255, 99, 132, 0.2)",
               "rgba(54, 162, 235, 0.2)",
               "rgba(255, 206, 86, 0.2)",
               "rgba(75, 192, 192, 0.2)",
               "rgba(153, 102, 255, 0.2)",
               "rgba(255, 159, 64, 0.2)",
            ],
            borderColor: [
               "rgba(255, 99, 132, 1)",
               "rgba(54, 162, 235, 1)",
               "rgba(255, 206, 86, 1)",
               "rgba(75, 192, 192, 1)",
               "rgba(153, 102, 255, 1)",
               "rgba(255, 159, 64, 1)",
            ],
            borderWidth: 1,
         },
      ],
   };
   return (
      <div>
          <Doughnut data={data} options={options}/>
      </div>
   );
};

export default TopBuyingPurchaser;
